#include <iostream>
#include <vector>
#include <string>
#include <utility> // For std::pair

// The countWords function definition is assumed to be provided by the user's code.
// Its signature is: int countWords(const std::string& sentence);

int main() {
    std::vector<std::pair<std::string, int>> test_cases = {
        {"", 0},
        {"hello", 1},
        {"hello world", 2},
        {"  hello world  ", 2},
        {"hello   world", 2},
        {"   ", 0},
        {"one", 1},
        {"multiple words test string", 4}
    };

    bool all_passed = true;
    for (size_t i = 0; i < test_cases.size(); ++i) {
        const auto& tc = test_cases[i];
        std::string input = tc.first;
        int expected = tc.second;
        int actual = countWords(input); // Call to the function under test

        if (actual == expected) {
            std::cout << "Test " << i + 1 << " Passed: Input=\"" << input << "\", Expected=" << expected << ", Got=" << actual << std::endl;
        } else {
            std::cout << "Test " << i + 1 << " FAILED: Input=\"" << input << "\", Expected=" << expected << ", Got=" << actual << std::endl;
            all_passed = false;
        }
    }

    if (all_passed) {
        std::cout << "All tests passed!" << std::endl;
        return 0;
    } else {
        std::cout << "Some tests failed." << std::endl;
        return 1;
    }
}
